+
+    /// Closes the client connection.
+    pub fn close(mut self) {
+        // Close the transport
+        let _ = self.transport.close();
+
+        // Kill the subprocess if still running
+        let _ = self.child.kill();
+        let _ = self.child.wait();
+    }
